# Utility module importing Shape classes
from shapes import Shape

def describe_shape(s: Shape) -> str:
    return s.name + ": area=" + str(s.area()) + ", perim=" + str(s.perimeter())

def sum_areas(shapes: list[Shape]) -> float:
    total: float = 0.0
    for s in shapes:
        total = total + s.area()
    return total
